{
  "family": "patch_test_pass",
  "case_id": "rank_players_score_name_tiebreak",
  "bug_category": "sorting_ranking_tiebreaks",
  "difficulty": "medium",
  "user": "In the Rust crate at {project_root}, fix the ranking logic in src/lib.rs so the tests pass. Rankings should sort by score descending, then by name ascending, and assign the same rank to tied entries while the next distinct entry skips ahead accordingly.",
  "expected_tool_sequence": ["read_file", "apply_patch", "cargo_test"],
  "expected_output": null,
  "files": {
    "Cargo.toml": "[package]
name = "rank_players_score_name_tiebreak"
version = "0.1.0"
edition = "2021"

[dependencies]
",
    "src/lib.rs": "#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Player {
    pub name: String,
    pub score: u32,
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct RankedPlayer {
    pub rank: usize,
    pub name: String,
    pub score: u32,
}

pub fn rank_players(players: &[Player]) -> Vec<RankedPlayer> {
    let mut entries = players.to_vec();
    entries.sort_by(|a, b| a.score.cmp(&b.score).then_with(|| a.name.cmp(&b.name)));

    let mut out = Vec::with_capacity(entries.len());
    for (idx, p) in entries.into_iter().enumerate() {
        out.push(RankedPlayer {
            rank: idx + 1,
            name: p.name,
            score: p.score,
        });
    }
    out
}

#[cfg(test)]
mod tests {
    use super::*;

    fn p(name: &str, score: u32) -> Player {
        Player {
            name: name.to_string(),
            score,
        }
    }

    #[test]
    fn sorts_by_score_desc_then_name_asc() {
        let ranked = rank_players(&[
            p("zoe", 12),
            p("amy", 20),
            p("mike", 12),
            p("bob", 20),
        ]);

        let pairs: Vec<(usize, String, u32)> = ranked
            .into_iter()
            .map(|r| (r.rank, r.name, r.score))
            .collect();

        assert_eq!(
            pairs,
            vec![
                (1, "amy".to_string(), 20),
                (1, "bob".to_string(), 20),
                (3, "mike".to_string(), 12),
                (3, "zoe".to_string(), 12),
            ]
        );
    }

    #[test]
    fn leaves_gaps_after_ties() {
        let ranked = rank_players(&[
            p("kai", 30),
            p("ivy", 30),
            p("uma", 25),
            p("abe", 25),
            p("neo", 10),
        ]);

        let ranks: Vec<usize> = ranked.into_iter().map(|r| r.rank).collect();
        assert_eq!(ranks, vec![1, 1, 3, 3, 5]);
    }
}
"
  },
  "steps": [
    {
      "tool": "read_file",
      "file_path": "src/lib.rs"
    },
    {
      "tool": "apply_patch",
      "file_path": "src/lib.rs",
      "find": "pub fn rank_players(players: &[Player]) -> Vec<RankedPlayer> {
    let mut entries = players.to_vec();
    entries.sort_by(|a, b| a.score.cmp(&b.score).then_with(|| a.name.cmp(&b.name)));

    let mut out = Vec::with_capacity(entries.len());
    for (idx, p) in entries.into_iter().enumerate() {
        out.push(RankedPlayer {
            rank: idx + 1,
            name: p.name,
            score: p.score,
        });
    }
    out
}
",
      "replace": "pub fn rank_players(players: &[Player]) -> Vec<RankedPlayer> {
    let mut entries = players.to_vec();
    entries.sort_by(|a, b| b.score.cmp(&a.score).then_with(|| a.name.cmp(&b.name)));

    let mut out = Vec::with_capacity(entries.len());
    let mut current_rank = 0usize;
    let mut last_score = None;

    for (idx, p) in entries.into_iter().enumerate() {
        if last_score != Some(p.score) {
            current_rank = idx + 1;
            last_score = Some(p.score);
        }

        out.push(RankedPlayer {
            rank: current_rank,
            name: p.name,
            score: p.score,
        });
    }
    out
}
"
    },
    {
      "tool": "cargo_test",
      "expect_status": "success"
    }
  ],
  "final": "FINAL: Updated ranking to sort by descending score with ascending-name tiebreaks and to assign competition ranks with gaps after ties."
}

{
  "family": "patch_test_pass",
  "case_id": "department_totals_skip_refunds_and_zero_rows",
  "bug_category": "aggregation_reporting",
  "difficulty": "medium",
  "user": "In the Rust crate at {project_root}, fix the reporting logic in src/lib.rs so the tests pass. The summary should aggregate only positive amounts by department, skip zero-total departments, and order rows by total descending with department name ascending as a tiebreaker.",
  "expected_tool_sequence": [
    "read_file",
    "apply_patch",
    "cargo_test"
  ],
  "expected_output": null,
  "files": {
    "Cargo.toml": "[package]
name = "department_report"
version = "0.1.0"
edition = "2021"

[dependencies]
",
    "src/lib.rs": "use std::collections::BTreeMap;

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Entry {
    pub department: &'static str,
    pub amount: i32,
}

pub fn summarize(entries: &[Entry]) -> String {
    let mut totals: BTreeMap<&str, i32> = BTreeMap::new();
    for entry in entries {
        *totals.entry(entry.department).or_insert(0) += entry.amount;
    }

    let mut rows: Vec<_> = totals.into_iter().collect();
    rows.sort_by(|a, b| a.0.cmp(b.0));

    rows.into_iter()
        .map(|(dept, total)| format!("{dept}:{total}"))
        .collect::<Vec<_>>()
        .join("\n")
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn reports_positive_totals_only_sorted_by_total_desc_then_name() {
        let entries = [
            Entry { department: "ops", amount: 5 },
            Entry { department: "sales", amount: 10 },
            Entry { department: "ops", amount: 7 },
            Entry { department: "sales", amount: -3 },
            Entry { department: "hr", amount: 4 },
            Entry { department: "legal", amount: 0 },
            Entry { department: "hr", amount: 8 },
            Entry { department: "alpha", amount: 12 },
            Entry { department: "beta", amount: 12 },
            Entry { department: "ops", amount: -2 },
        ];

        let report = summarize(&entries);
        assert_eq!(report, "alpha:12\nbeta:12\nhr:12\nops:12\nsales:10");
    }

    #[test]
    fn omits_departments_with_only_zero_or_negative_entries() {
        let entries = [
            Entry { department: "ops", amount: 0 },
            Entry { department: "ops", amount: -2 },
            Entry { department: "sales", amount: 3 },
            Entry { department: "sales", amount: 0 },
            Entry { department: "hr", amount: -1 },
        ];

        let report = summarize(&entries);
        assert_eq!(report, "sales:3");
    }
}
"
  },
  "steps": [
    {
      "tool": "read_file",
      "file_path": "src/lib.rs"
    },
    {
      "tool": "apply_patch",
      "file_path": "src/lib.rs",
      "find": "pub fn summarize(entries: &[Entry]) -> String {
    let mut totals: BTreeMap<&str, i32> = BTreeMap::new();
    for entry in entries {
        *totals.entry(entry.department).or_insert(0) += entry.amount;
    }

    let mut rows: Vec<_> = totals.into_iter().collect();
    rows.sort_by(|a, b| a.0.cmp(b.0));

    rows.into_iter()
        .map(|(dept, total)| format!("{dept}:{total}"))
        .collect::<Vec<_>>()
        .join("\n")
}
",
      "replace": "pub fn summarize(entries: &[Entry]) -> String {
    let mut totals: BTreeMap<&str, i32> = BTreeMap::new();
    for entry in entries {
        if entry.amount > 0 {
            *totals.entry(entry.department).or_insert(0) += entry.amount;
        }
    }

    let mut rows: Vec<_> = totals.into_iter().filter(|(_, total)| *total > 0).collect();
    rows.sort_by(|a, b| b.1.cmp(&a.1).then_with(|| a.0.cmp(b.0)));

    rows.into_iter()
        .map(|(dept, total)| format!("{dept}:{total}"))
        .collect::<Vec<_>>()
        .join("\n")
}
"
    },
    {
      "tool": "cargo_test",
      "expect_status": "success"
    }
  ],
  "final": "FINAL: Updated summarize to ignore non-positive entries, drop zero-total departments, and sort report rows by descending totals with department-name tiebreaks."
}

{
  "family": "patch_test_pass",
  "case_id": "workflow_state_transition_rules",
  "bug_category": "state_transitions",
  "difficulty": "hard",
  "user": "In the Rust crate at {project_root}, fix the workflow state transition logic in src/lib.rs so the tests pass. Preserve the existing API and update only the implementation needed.",
  "expected_tool_sequence": ["read_file", "apply_patch", "cargo_test"],
  "expected_output": null,
  "files": {
    "Cargo.toml": "[package]
name = "workflow_state_transition_rules"
version = "0.1.0"
edition = "2021"

[lib]
path = "src/lib.rs"
",
    "src/lib.rs": "#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Status {
    Draft,
    Submitted,
    Approved,
    Rejected,
    Archived,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Event {
    Submit,
    Approve,
    Reject,
    Revise,
    Archive,
    Restore,
}

pub fn apply_event(status: Status, event: Event, has_reviewer: bool, has_changes_requested: bool) -> Status {
    match event {
        Event::Submit => Status::Submitted,
        Event::Approve => {
            if has_reviewer {
                Status::Approved
            } else {
                status
            }
        }
        Event::Reject => Status::Rejected,
        Event::Revise => Status::Draft,
        Event::Archive => Status::Archived,
        Event::Restore => {
            if has_changes_requested {
                Status::Draft
            } else {
                Status::Approved
            }
        }
    }
}

#[cfg(test)]
mod tests {
    use super::{apply_event, Event, Status};

    #[test]
    fn submit_only_moves_draft_to_submitted() {
        assert_eq!(apply_event(Status::Draft, Event::Submit, false, false), Status::Submitted);
        assert_eq!(apply_event(Status::Rejected, Event::Submit, false, false), Status::Rejected);
        assert_eq!(apply_event(Status::Approved, Event::Submit, true, false), Status::Approved);
    }

    #[test]
    fn approve_requires_submitted_and_reviewer() {
        assert_eq!(apply_event(Status::Submitted, Event::Approve, true, false), Status::Approved);
        assert_eq!(apply_event(Status::Submitted, Event::Approve, false, false), Status::Submitted);
        assert_eq!(apply_event(Status::Draft, Event::Approve, true, false), Status::Draft);
    }

    #[test]
    fn reject_only_from_submitted() {
        assert_eq!(apply_event(Status::Submitted, Event::Reject, true, false), Status::Rejected);
        assert_eq!(apply_event(Status::Draft, Event::Reject, true, false), Status::Draft);
        assert_eq!(apply_event(Status::Approved, Event::Reject, true, false), Status::Approved);
    }

    #[test]
    fn revise_only_from_rejected_with_changes_requested() {
        assert_eq!(apply_event(Status::Rejected, Event::Revise, false, true), Status::Draft);
        assert_eq!(apply_event(Status::Rejected, Event::Revise, false, false), Status::Rejected);
        assert_eq!(apply_event(Status::Submitted, Event::Revise, false, true), Status::Submitted);
    }

    #[test]
    fn archive_only_from_terminal_review_states() {
        assert_eq!(apply_event(Status::Approved, Event::Archive, true, false), Status::Archived);
        assert_eq!(apply_event(Status::Rejected, Event::Archive, false, true), Status::Archived);
        assert_eq!(apply_event(Status::Draft, Event::Archive, false, false), Status::Draft);
        assert_eq!(apply_event(Status::Submitted, Event::Archive, true, false), Status::Submitted);
    }

    #[test]
    fn restore_from_archived_depends_on_pending_changes() {
        assert_eq!(apply_event(Status::Archived, Event::Restore, false, true), Status::Draft);
        assert_eq!(apply_event(Status::Archived, Event::Restore, false, false), Status::Approved);
        assert_eq!(apply_event(Status::Approved, Event::Restore, false, true), Status::Approved);
    }
}
"
  },
  "steps": [
    {
      "tool": "read_file",
      "file_path": "src/lib.rs"
    },
    {
      "tool": "apply_patch",
      "file_path": "src/lib.rs",
      "find": "pub fn apply_event(status: Status, event: Event, has_reviewer: bool, has_changes_requested: bool) -> Status {
    match event {
        Event::Submit => Status::Submitted,
        Event::Approve => {
            if has_reviewer {
                Status::Approved
            } else {
                status
            }
        }
        Event::Reject => Status::Rejected,
        Event::Revise => Status::Draft,
        Event::Archive => Status::Archived,
        Event::Restore => {
            if has_changes_requested {
                Status::Draft
            } else {
                Status::Approved
            }
        }
    }
}
",
      "replace": "pub fn apply_event(status: Status, event: Event, has_reviewer: bool, has_changes_requested: bool) -> Status {
    match event {
        Event::Submit => match status {
            Status::Draft => Status::Submitted,
            _ => status,
        },
        Event::Approve => match status {
            Status::Submitted if has_reviewer => Status::Approved,
            _ => status,
        },
        Event::Reject => match status {
            Status::Submitted => Status::Rejected,
            _ => status,
        },
        Event::Revise => match status {
            Status::Rejected if has_changes_requested => Status::Draft,
            _ => status,
        },
        Event::Archive => match status {
            Status::Approved | Status::Rejected => Status::Archived,
            _ => status,
        },
        Event::Restore => match status {
            Status::Archived if has_changes_requested => Status::Draft,
            Status::Archived => Status::Approved,
            _ => status,
        },
    }
}
"
    },
    {
      "tool": "cargo_test",
      "expect_status": "success"
    }
  ],
  "final": "FINAL: Patched src/lib.rs to enforce valid workflow transitions by current status and flags; cargo test passes."
}

