    "src/lib.rs": "pub fn parse_records(input: &str) -> Result<Vec<(String, u32)>, String> {
    let mut out = Vec::new();

    for (idx, line) in input.lines().enumerate() {
        let line = line.trim();
        if line.is_empty() {
            continue;
        }

        let parts: Vec<&str> = line.split(',').collect();
        if parts.len() < 2 {
            return Err(format!("line {}: expected 2 fields", idx + 1));
        }

        let name = parts[0].trim();
        if name.is_empty() {
            return Err(format!("line {}: empty name", idx + 1));
        }

        let qty = parts[1]
            .trim()
            .parse::<u32>()
            .map_err(|_| format!("line {}: invalid quantity", idx + 1))?;

        out.push((name.to_string(), qty));
    }

    Ok(out)
}

