    match event {
        Event::Connected => "ready",
        Event::Disconnected { retryable } => {
            if retryable { "offline" } else { "dead" }
        }
        Event::Data { valid } => {
            if valid { "accepted" } else { "rejected" }
        }
        Event::Timeout { attempt } => {
            if attempt == 0 { "retry" } else { "dead" }
        }
    }
}

