    "src/main.rs": "use std::collections::BTreeMap;

#[derive(Clone, Copy, Debug, PartialEq, Eq)]
enum Status {
    Open,
    InProgress,
    Closed,
}

#[derive(Clone, Copy, Debug)]
enum Event<'a> {
    Assign(&'a str),
    Start,
    Hold,
    Release,
    Resolve,
    Reopen,
    Unassign,
}

#[derive(Clone, Debug)]
struct Ticket {
    status: Status,
    assignee: Option<String>,
    on_hold: bool,
}

impl Ticket {
    fn new() -> Self {
        Self {
            status: Status::Open,
            assignee: None,
            on_hold: false,
        }
    }

    fn apply(&mut self, event: Event<'_>) {
        match event {
            Event::Assign(name) => {
                self.assignee = Some(name.to_string());
            }
            Event::Start => {
                if self.status != Status::Closed {
                    self.status = Status::InProgress;
                }
            }
            Event::Hold => {
                if self.status == Status::InProgress {
                    self.on_hold = true;
                }
            }
            Event::Release => {
                self.on_hold = false;
            }
            Event::Resolve => {
                self.status = Status::Closed;
            }
            Event::Reopen => {
                self.status = Status::InProgress;
            }
            Event::Unassign => {
                if self.status != Status::Closed {
                    self.assignee = None;
                }
            }
        }
    }

    fn render(&self, id: &str) -> String {
        let status = match self.status {
            Status::Open => "open",
            Status::InProgress => "in_progress",
            Status::Closed => "closed",
        };
        let assignee = self.assignee.as_deref().unwrap_or("none");
        format!("{}: {} (assignee={}, hold={})", id, status, assignee, self.on_hold)
    }
}

