        Some(v) if !v.is_empty() => {}
        _ => return Err("missing id"),
    }

    match score {
        Some(v) if v.parse::<u32>().is_ok() => {}
        Some(_) => return Err("bad score"),
        None => return Err("missing score"),
    }

    match active {
        Some("true") | Some("false") => {}
        _ => return Err("bad active"),
    }

    Ok(())
}

