pub struct Player {
    pub name: &'static str,
    pub score: u32,
    pub wins: u32,
    pub penalty: u32,
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct RankedPlayer {
    pub rank: usize,
    pub name: &'static str,
    pub score: u32,
    pub wins: u32,
    pub penalty: u32,
}

pub fn rank_players(players: &[Player]) -> Vec<RankedPlayer> {
    let mut sorted = players.to_vec();
    sorted.sort_by(|a, b| {
        b.score
            .cmp(&a.score)
            .then_with(|| a.penalty.cmp(&b.penalty))
            .then_with(|| a.name.cmp(&b.name))
    });

    let mut out = Vec::with_capacity(sorted.len());
    for (idx, p) in sorted.into_iter().enumerate() {
        let rank = if idx > 0 {
            let prev = &out[idx - 1];
            if prev.score == p.score && prev.penalty == p.penalty {
                prev.rank
            } else {
                idx + 1
            }
        } else {
            1
        };

        out.push(RankedPlayer {
            rank,
            name: p.name,
            score: p.score,
            wins: p.wins,
            penalty: p.penalty,
        });
    }
    out
}

