pub struct Entry {
    pub name: &'static str,
    pub score: u32,
    pub penalties: u32,
    pub last_submission: u32,
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct RankedEntry {
    pub rank: usize,
    pub name: &'static str,
    pub score: u32,
    pub penalties: u32,
    pub last_submission: u32,
}

pub fn rank_entries(entries: &[Entry]) -> Vec<RankedEntry> {
    let mut items = entries.to_vec();
    items.sort_by(|a, b| {
        b.score
            .cmp(&a.score)
            .then_with(|| b.penalties.cmp(&a.penalties))
            .then_with(|| b.last_submission.cmp(&a.last_submission))
            .then_with(|| b.name.cmp(&a.name))
    });

    let mut out = Vec::with_capacity(items.len());
    let mut current_rank = 1;

    for (i, item) in items.into_iter().enumerate() {
        if i > 0 {
            let prev = &out[i - 1];
            if prev.score != item.score || prev.penalties != item.penalties {
                current_rank = i + 1;
            }
        }

        out.push(RankedEntry {
            rank: current_rank,
            name: item.name,
            score: item.score,
            penalties: item.penalties,
            last_submission: item.last_submission,
        });
    }

    out
}

