    "src/lib.rs": "#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Player {
    pub name: String,
    pub score: u32,
    pub penalties: u32,
    pub joined_at: u32,
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct RankedPlayer {
    pub rank: usize,
    pub name: String,
    pub score: u32,
    pub penalties: u32,
}

pub fn rank_players(players: &[Player]) -> Vec<RankedPlayer> {
    let mut items = players.to_vec();
    items.sort_by(|a, b| {
        b.score
            .cmp(&a.score)
            .then_with(|| a.name.cmp(&b.name))
    });

    let mut out = Vec::with_capacity(items.len());
    let mut prev_score = None;
    let mut rank = 0usize;

    for p in items {
        if prev_score != Some(p.score) {
            rank += 1;
            prev_score = Some(p.score);
        }
        out.push(RankedPlayer {
            rank,
            name: p.name,
            score: p.score,
            penalties: p.penalties,
        });
    }

    out
}

