    "src/lib.rs": "#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Config {
    pub host: String,
    pub port: u16,
    pub use_tls: bool,
}

#[derive(Debug, Clone, Default)]
pub struct PartialConfig {
    pub host: Option<String>,
    pub port: Option<u16>,
    pub use_tls: Option<bool>,
}

impl Config {
    pub fn defaults() -> Self {
        Self {
            host: "localhost".to_string(),
            port: 8080,
            use_tls: false,
        }
    }
}

pub fn merge_config(
    defaults: Config,
    file_cfg: PartialConfig,
    env_cfg: PartialConfig,
    cli_cfg: PartialConfig,
) -> Config {
    Config {
        host: cli_cfg
            .host
            .or(env_cfg.host)
            .or(file_cfg.host)
            .unwrap_or(defaults.host),
        port: file_cfg
            .port
            .or(env_cfg.port)
            .or(cli_cfg.port)
            .unwrap_or(defaults.port),
        use_tls: file_cfg
            .use_tls
            .or(cli_cfg.use_tls)
            .or(env_cfg.use_tls)
            .unwrap_or(defaults.use_tls),
    }
}

