pub struct Entry {
    pub name: &'static str,
    pub score: u32,
    pub solved: u32,
    pub penalty: u32,
}

pub fn leaderboard(entries: &[Entry]) -> Vec<String> {
    let mut items = entries.to_vec();
    items.sort_by(|a, b| {
        a.score
            .cmp(&b.score)
            .then(a.solved.cmp(&b.solved))
            .then(a.penalty.cmp(&b.penalty))
            .then(a.name.cmp(b.name))
    });

    let mut out = Vec::new();
    let mut last: Option<(u32, u32, u32)> = None;
    let mut rank = 0usize;

    for (i, e) in items.iter().enumerate() {
        let key = (e.score, e.solved, e.penalty);
        if last != Some(key) {
            rank = i + 1;
            last = Some(key);
        }
        out.push(format!("{}. {} [{}|{}|{}]", rank, e.name, e.score, e.solved, e.penalty));
    }

    out
}

