pub struct Sale<'a> {
    pub category: &'a str,
    pub qty: i32,
}

pub fn render_report(sales: &[Sale<'_>], categories: &[&str]) -> String {
    let mut totals: BTreeMap<&str, i32> = BTreeMap::new();

