        assert_eq!(apply_event(Status::Closed, Event::Reopen), Status::Open);
    }

    #[test]
    fn close_requires_resolution_first() {
        assert_eq!(apply_event(Status::InProgress, Event::Close), Status::InProgress);
        assert_eq!(apply_event(Status::Open, Event::Close), Status::Open);
    }

    #[test]
    fn sequence_preserves_work_after_reopen() {
        let events = [Event::Start, Event::Resolve, Event::Reopen, Event::Resolve, Event::Close];
        assert_eq!(apply_events(Status::Open, &events), Status::Closed);
    }

