pub enum Action {
    Create { dry_run: bool },
    Delete { force: bool },
    Sync { full: bool },
    Inspect,
}

pub fn dispatch(action: Action) -> &'static str {
    match action {
        Action::Create { .. } => "create",
        Action::Delete { .. } => "delete",
        Action::Sync { .. } => "sync",
        Action::Inspect => "inspect",
    }
}

pub fn execute(action: Action) -> &'static str {
    match action {
        Action::Create { dry_run } => {
            if dry_run {
                "create"
            } else {
                "created"
            }
        }
        Action::Delete { force } => {
            if force {
                "deleted"
            } else {
                "delete"
            }
        }
        Action::Sync { full } => {
            if full {
                "synced"
            } else {
                "sync"
            }
        }
        Action::Inspect => "inspect",
    }
}

