        let Some((k, v)) = line.split_once('=') else {
            return Err("invalid line".to_string());
        };
        current_map.insert(k.trim().to_string(), v.trim().to_string());
    }

    if let Some(name) = current_name {
        sections.push((name, current_map));
    }

    let mut items = Vec::new();
    for (name, map) in sections {
        let id = map.get("id").cloned().unwrap_or(name);
        let enabled = map
            .get("enabled")
            .map(|v| v == "true")
            .unwrap_or(false);
        let tags = map
            .get("tags")
            .map(|v| {
                v.split(',')
                    .map(|s| s.trim().to_string())
                    .filter(|s| !s.is_empty())
                    .collect::<Vec<_>>()
            })
            .unwrap_or_default();

        items.push(Item { id, enabled, tags });
    }

    Ok(items)
}

