pub struct Player {
    pub name: String,
    pub score: u32,
    pub wins: u32,
}

pub fn rank_players(players: &[Player]) -> Vec<String> {
    let mut items = players.to_vec();
    items.sort_by(|a, b| {
        b.score
            .cmp(&a.score)
            .then_with(|| a.name.cmp(&b.name))
    });

    let mut out = Vec::new();
    for (i, p) in items.iter().enumerate() {
        out.push(format!("{}. {} ({}, {} wins)", i + 1, p.name, p.score, p.wins));
    }
    out
}

