#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Event {
    Start,
    Block,
    Unblock,
    Complete,
    Archive,
    Reopen,
    Retry,
}

pub fn apply_events(events: &[Event]) -> Status {
    let mut status = Status::New;
    for event in events {
        status = match (status, *event) {
            (Status::New, Event::Start) => Status::Active,
            (Status::New, Event::Archive) => Status::Archived,
            (Status::Active, Event::Block) => Status::Blocked,
            (Status::Active, Event::Complete) => Status::Done,
