pub struct Config {
    pub host: String,
    pub port: u16,
    pub tls: bool,
    pub timeout_ms: u64,
    pub profile: String,
}

#[derive(Debug, Clone, Default)]
pub struct PartialConfig {
    pub host: Option<String>,
    pub port: Option<u16>,
    pub tls: Option<bool>,
    pub timeout_ms: Option<u64>,
    pub profile: Option<String>,
}

impl Config {
    pub fn defaults() -> Self {
        Self {
            host: "127.0.0.1".to_string(),
            port: 8080,
            tls: false,
            timeout_ms: 3000,
            profile: "dev".to_string(),
        }
    }
}

pub fn merge_config(
    defaults: Config,
    file: PartialConfig,
    env: PartialConfig,
    cli: PartialConfig,
) -> Config {
    let mut out = defaults;

    apply_partial(&mut out, &cli);
    apply_partial(&mut out, &env);
    apply_partial(&mut out, &file);

    if out.timeout_ms == 0 {
        out.timeout_ms = 3000;
    }

    if out.profile == "prod" {
        out.tls = false;
    }

    out
}

fn apply_partial(base: &mut Config, layer: &PartialConfig) {
    if let Some(host) = &layer.host {
        base.host = host.clone();
    }
    if let Some(port) = layer.port {
        base.port = port;
    }
    if let Some(tls) = layer.tls {
        base.tls = tls;
    }
    if let Some(timeout_ms) = layer.timeout_ms {
        base.timeout_ms = timeout_ms;
    }
    if let Some(profile) = &layer.profile {
        base.profile = profile.clone();
    }
}

