#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Sale {
    pub region: &'static str,
    pub reps: u32,
    pub units: u32,
    pub returned: u32,
}

pub fn region_summary(rows: &[Sale]) -> String {
    let mut totals: BTreeMap<&str, (u32, u32, u32)> = BTreeMap::new();

    for row in rows {
        let entry = totals.entry(row.region).or_insert((0, 0, 0));
        entry.0 += row.reps;
        entry.1 += row.units;
        entry.2 += row.returned;
