pub struct Player<'a> {
    pub name: &'a str,
    pub score: u32,
    pub wins: u32,
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct RankedPlayer<'a> {
    pub rank: usize,
    pub name: &'a str,
    pub score: u32,
    pub wins: u32,
}

pub fn rank_players<'a>(players: &[Player<'a>]) -> Vec<RankedPlayer<'a>> {
    let mut ordered = players.to_vec();
    ordered.sort_by(|a, b| {
        b.score
            .cmp(&a.score)
            .then_with(|| a.name.cmp(b.name))
            .then_with(|| b.wins.cmp(&a.wins))
    });

    let mut out = Vec::with_capacity(ordered.len());
    let mut last_score = None;
    let mut current_rank = 0;

    for (idx, p) in ordered.into_iter().enumerate() {
        if last_score != Some(p.score) {
            current_rank = idx + 1;
            last_score = Some(p.score);
        }
        out.push(RankedPlayer {
            rank: current_rank,
            name: p.name,
            score: p.score,
            wins: p.wins,
        });
    }

    out
}

