#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Record {
    pub id: String,
    pub kind: String,
    pub flags: Vec<String>,
    pub qty: u32,
}

pub fn parse_records(input: &str) -> Result<Vec<Record>, String> {
    let mut out = Vec::new();

    for (block_idx, block) in input.split("\n\n").enumerate() {
        if block.trim().is_empty() {
            continue;
        }

        let mut id = None;
        let mut kind = None;
        let mut flags = Vec::new();
        let mut qty = None;

        for raw_line in block.lines() {
            let line = raw_line.trim();
            if line.is_empty() {
                continue;
            }

            let (key, value) = line
                .split_once(':')
                .ok_or_else(|| format!("block {} has invalid line", block_idx + 1))?;
            let key = key.trim();
            let value = value.trim();

            match key {
