    pub goals_for: u32,
}

pub fn standings_table(results: &[(&str, u32, u32, &str)]) -> Vec<TeamStanding> {
    let mut table: BTreeMap<String, TeamStanding> = BTreeMap::new();

    for &(home, home_goals, away_goals, away) in results {
        let home_points = if home_goals > away_goals {
            3
        } else if home_goals == away_goals {
            1
        } else {
            0
        };
        let away_points = if away_goals > home_goals {
            3
        } else if away_goals == home_goals {
            1
        } else {
            0
        };

        let home_entry = table.entry(home.to_string()).or_insert(TeamStanding {
            team: home.to_string(),
            points: 0,
            goal_diff: 0,
            goals_for: 0,
        });
        home_entry.points += home_points;
        home_entry.goal_diff += home_goals as i32 - away_goals as i32;
        home_entry.goals_for += home_goals;

        let away_entry = table.entry(away.to_string()).or_insert(TeamStanding {
            team: away.to_string(),
            points: 0,
            goal_diff: 0,
            goals_for: 0,
        });
        away_entry.points += away_points;
        away_entry.goal_diff += away_goals as i32 - home_goals as i32;
        away_entry.goals_for += away_goals;
    }

    let mut rows: Vec<_> = table.into_values().collect();
    rows.sort_by(|a, b| {
        b.points
            .cmp(&a.points)
            .then_with(|| a.team.cmp(&b.team))
    });
    rows
}

