    Warmup,
    Cleanup { dry_run: bool },
    Backup { target: Option<&'static str> },
    Deploy { env: &'static str, approved: bool },
}

enum Outcome {
    Ok(&'static str),
    Warn(&'static str),
    Err(&'static str),
}

fn exec(cmd: Cmd) -> Outcome {
    match cmd {
        Cmd::Warmup => Outcome::Ok("cache warmup"),
        Cmd::Cleanup { dry_run } => {
            if dry_run {
                Outcome::Ok("cleanup skipped")
            } else {
                Outcome::Ok("cleanup removed temp files")
            }
        }
        Cmd::Backup { target } => match target {
            Some("remote") => Outcome::Ok("backup sent to remote"),
            Some("local") => Outcome::Warn("backup wrote local copy"),
            None => Outcome::Err("backup missing target"),
            _ => Outcome::Err("backup unsupported target"),
        },
        Cmd::Deploy { env, approved } => match (env, approved) {
            ("prod", true) => Outcome::Ok("deploy started: prod"),
            ("prod", false) => Outcome::Warn("deploy pending approval"),
            ("stage", _) => Outcome::Ok("deploy started: stage"),
            _ => Outcome::Err("deploy unknown environment"),
        },
    }
}

fn render(outcome: Outcome) -> String {
    match outcome {
        Outcome::Ok(msg) => format!("ok {}", msg),
        Outcome::Warn(msg) => format!("warn {}", msg),
        Outcome::Err(msg) => format!("err {}", msg),
    }
}

fn main() {
    let cmds = [
        Cmd::Warmup,
        Cmd::Cleanup { dry_run: true },
        Cmd::Backup { target: None },
        Cmd::Deploy {
            env: "prod",
            approved: false,
