    let mut warn = 0;
    let mut err = 0;

    for cmd in cmds {
        let outcome = exec(cmd);
        match outcome {
            Outcome::Ok(_) => ok += 1,
            Outcome::Warn(_) => warn += 1,
            Outcome::Err(_) => err += 1,
        }
        println!("{}", render(outcome));
    }

    println!("summary ok={} warn={} err={}", ok, warn, err);
}
