        if line.is_empty() {
            continue;
        }
        match validate_line(line) {
            None => valid += 1,
            Some(err) => invalid.push(format!("line {}: {}", idx + 1, err)),
        }
    }

    println!("valid: {}", valid);
    println!("invalid:");
