name = "ticket_state_transition_closure_rules"
version = "0.1.0"
edition = "2021"

[dependencies]
",
    "src/main.rs": "use std::collections::BTreeMap;

#[derive(Clone, Copy)]
enum Status {
    Open,
    InProgress,
    Closed,
    Reopened,
}

impl Status {
    fn as_str(self) -> &'static str {
        match self {
            Status::Open => "Open",
            Status::InProgress => "InProgress",
            Status::Closed => "Closed",
            Status::Reopened => "Reopened",
        }
    }
}

fn apply_event(state: Status, event: &str) -> Status {
    match event {
        "start" => Status::InProgress,
        "close" => Status::Closed,
        "reopen" => Status::Open,
        _ => state,
    }
}

fn main() {
    let events = [
        ("A", "start"),
        ("A", "close"),
        ("A", "reopen"),
        ("A", "close"),
        ("B", "start"),
        ("C", "start"),
        ("C", "close"),
        ("C", "reopen"),
    ];

    let mut states: BTreeMap<&str, Status> = BTreeMap::new();

    for (ticket, event) in events {
        let current = states.get(ticket).copied().unwrap_or(Status::Open);
        let next = apply_event(current, event);
        states.insert(ticket, next);
    }

    for ticket in ["A", "B", "C"] {
        println!("{}:{}", ticket, states.get(ticket).unwrap().as_str());
    }
}
