fn classify(event: &Event) -> &'static str {
    match event {
        Event::Completed { retries, warnings } => {
            if *retries > 0 || *warnings > 0 {
                "warn"
            } else {
                "ok"
            }
        }
        Event::TimedOut { partial } => {
            if *partial {
                "skip"
            } else {
                "fail"
            }
        }
        Event::Rejected { code } => {
            if *code >= 500 {
                "skip"
            } else {
                "fail"
            }
        }
        Event::Cancelled => "fail",
    }
}

