edition = "2021"
",
    "src/main.rs": "const INPUT: &str = "alice|30|7\nbob|xx|5\n|19|4\ncarol|28|-1\ned|22|0";

fn parse_line(line_no: usize, line: &str) -> Result<(String, u32, i32), String> {
    let parts: Vec<&str> = line.split('|').collect();
    if parts.len() != 3 {
        return Err(format!("line {}: wrong field count", line_no));
    }

    let name = parts[0].to_string();
    let age: u32 = parts[1]
        .parse()
        .map_err(|_| format!("line {}: bad age", line_no))?;
    let score: i32 = parts[2]
        .parse()
        .map_err(|_| format!("line {}: bad score", line_no))?;

    Ok((name, age, score))
}

fn main() {
    let mut valid = Vec::new();
    let mut errors = Vec::new();

    for (i, line) in INPUT.lines().enumerate() {
        match parse_line(i + 1, line) {
            Ok((name, age, score)) => {
                if score < 0 {
                    errors.push(format!("line {}: negative score", i + 1));
                } else {
                    valid.push((name, age, score));
                }
            }
            Err(e) => errors.push(e),
        }
    }

    println!("valid: {}", valid.len());
    println!("invalid: {}", errors.len());
    for (name, age, score) in valid {
        println!("{} score={} age={}", name, score, age);
    }
    println!("errors:");
    for e in errors {
        println!("{}", e);
    }
}
