    "src/main.rs": "use std::collections::{BTreeMap, BTreeSet};

#[derive(Clone, Copy)]
struct Sale {
    region: &'static str,
    rep: &'static str,
    amount: i32,
    active: bool,
}

fn report(rows: &[Sale]) -> String {
    let mut totals: BTreeMap<&str, i32> = BTreeMap::new();
    let mut reps: BTreeMap<&str, BTreeSet<&str>> = BTreeMap::new();

    for row in rows {
        *totals.entry(row.region).or_insert(0) += row.amount;
        reps.entry(row.region).or_default().insert(row.rep);
    }

    let mut items: Vec<_> = totals.into_iter().collect();
    items.sort_by(|a, b| a.0.cmp(b.0));

    items
        .into_iter()
        .map(|(region, total)| {
            let rep_count = reps.get(region).map(|set| set.len()).unwrap_or(0);
            format!("{} | total={} | reps={}", region, total, rep_count)
        })
        .collect::<Vec<_>>()
        .join("\n")
}

