fn is_valid(id: u32, level: &str, code: u32) -> bool {
    if id == 0 {
        return false;
    }
    match level {
        "INFO" => code < 200,
        "WARN" => code < 500,
        "ERROR" => code >= 500,
        _ => false,
    }
}

