#[derive(Debug)]
struct Record {
    id: u32,
    name: String,
    score: u8,
    active: bool,
}

fn parse_line(line: &str) -> Result<Record, String> {
    let parts: Vec<&str> = line.split('|').collect();
    if parts.len() < 4 {
        return Err("wrong field count".to_string());
    }

    let id = parts[0].parse::<u32>().map_err(|_| "invalid id".to_string())?;
    let name = parts[1].to_string();
    let score = parts[2].parse::<u8>().map_err(|_| "invalid score".to_string())?;
    let active = match parts[3] {
        "true" => true,
        "false" => false,
        _ => false,
    };

    Ok(Record { id, name, score, active })
}

fn main() {
    let mut seen = HashSet::new();
    let mut out = Vec::new();

    for line in INPUT.lines() {
        match parse_line(line) {
            Ok(rec) => {
                if !seen.insert(rec.id) {
                    out.push(format!("ERR {} duplicate id", rec.id));
                    continue;
                }
                out.push(format!("OK {} {}", rec.id, rec.name));
            }
            Err(msg) => {
                let id = line.split('|').next().unwrap_or("?");
                out.push(format!("ERR {} {}", id, msg));
            }
        }
    }

    println!("{}", out.join("\n"));
}
