            format!("deleted: {}", name)
        }
        Command::Tag { name, tags } => {
            stats.ignored += 1;
            format!("tagged: {} [{}]", name, tags.join(","))
        }
        Command::Noop => {
            stats.ignored += 1;
            "ignored: noop".to_string()
        }
    }
}

