struct Booking {
    start: u32,
    end: u32,
}

fn overlaps(a: Booking, b: Booking) -> bool {
    a.start <= b.end && b.start <= a.end
}

fn can_book(schedule: &BTreeMap<&str, Vec<Booking>>, room: &str, request: Booking) -> bool {
    if let Some(existing) = schedule.get(room) {
        for &slot in existing {
            if overlaps(slot, request) {
                return false;
            }
        }
    }
    true
}

