#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Action {
    ReplyPong,
    UseCache,
    NetworkFetch,
    RetryFetch,
    ValidateOnly,
    Persist,
    SkipMissing,
    Delete,
    Refuse,
}

pub fn decide(input: Input) -> Action {
    match input {
        Input::Ping => Action::ReplyPong,
        Input::Fetch {
            cached: true,
            retries: _,
        } => Action::UseCache,
        Input::Fetch {
            cached: false,
            retries: 0,
