        Input::Fetch {
            cached: false,
            retries: _,
        } => Action::RetryFetch,
        Input::Save { dry_run: true } => Action::ValidateOnly,
        Input::Save { dry_run: false } => Action::Persist,
        Input::Remove {
            force: _,
            exists: false,
        } => Action::SkipMissing,
        Input::Remove {
            force: true,
            exists: true,
        } => Action::Delete,
        Input::Remove {
            force: false,
