    "src/main.rs": "use std::collections::BTreeMap;

#[derive(Clone, Debug, Default)]
struct TeamStat {
    gf: u32,
    ga: u32,
    pts: u32,
}

fn main() {
    let matches = [
        ("Hawks", 2_u32, "Owls", 1_u32),
        ("Foxes", 0, "Bears", 0),
        ("Lynx", 1, "Moles", 0),
        ("Owls", 3, "Foxes", 1),
        ("Bears", 2, "Moles", 1),
        ("Hawks", 1, "Lynx", 0),
        ("Owls", 1, "Bears", 0),
        ("Moles", 1, "Foxes", 2),
        ("Lynx", 1, "Owls", 1),
        ("Hawks", 2, "Moles", 1),
        ("Foxes", 0, "Hawks", 0),
        ("Bears", 2, "Lynx", 1),
    ];

    let mut table: BTreeMap<&str, TeamStat> = BTreeMap::new();

    for (home, hg, away, ag) in matches {
        {
            let home_stat = table.entry(home).or_default();
            home_stat.gf += hg;
            home_stat.ga += ag;
            if hg > ag {
                home_stat.pts += 3;
            } else if hg == ag {
                home_stat.pts += 1;
            }
        }
        {
            let away_stat = table.entry(away).or_default();
            away_stat.gf += ag;
            away_stat.ga += hg;
            if ag > hg {
                away_stat.pts += 3;
            } else if ag == hg {
                away_stat.pts += 1;
            }
        }
    }

    let mut rows: Vec<_> = table.into_iter().collect();
    rows.sort_by(|a, b| {
        let sa = a.1;
        let sb = b.1;
        sb.pts
            .cmp(&sa.pts)
            .then_with(|| (sb.gf as i32 - sb.ga as i32).cmp(&(sa.gf as i32 - sa.ga as i32)))
            .then_with(|| sb.gf.cmp(&sa.gf))
            .then_with(|| a.0.cmp(b.0))
    });

    for (idx, (name, stat)) in rows.iter().enumerate() {
        let gd = stat.gf as i32 - stat.ga as i32;
        println!(
            "{}. {} - {} pts (GF {}, GA {}, GD {:+})",
            idx + 1,
            name,
            stat.pts,
            stat.gf,
            stat.ga,
            gd
        );
    }
}
