A2 Escalated
A3 Reopened",
  "files": {
    "Cargo.toml": "[package]
name = "ticket_state_transition_audit"
version = "0.1.0"
edition = "2021"

[dependencies]
",
    "src/main.rs": "#[derive(Clone, Copy, Debug, PartialEq, Eq)]
enum Status {
    Open,
    InProgress,
    Resolved,
    Closed,
    Escalated,
    Reopened,
}

#[derive(Clone, Copy)]
enum Event {
    Start,
    Resolve,
    Close,
    Escalate,
    Reopen,
}

fn apply(mut status: Status, events: &[Event]) -> Status {
    for event in events {
        status = match (status, event) {
            (Status::Open, Event::Start) => Status::InProgress,
            (Status::Open, Event::Escalate) => Status::Escalated,
            (Status::InProgress, Event::Resolve) => Status::Resolved,
            (Status::InProgress, Event::Escalate) => Status::Escalated,
            (Status::Resolved, Event::Close) => Status::Closed,
            (Status::Resolved, Event::Reopen) => Status::Reopened,
            (Status::Escalated, Event::Resolve) => Status::Resolved,
            (Status::Escalated, Event::Close) => Status::Escalated,
            (Status::Closed, Event::Reopen) => Status::Reopened,
            (Status::Reopened, Event::Start) => Status::InProgress,
            _ => status,
        };
    }
    status
}

fn label(status: Status) -> &'static str {
    match status {
        Status::Open => "Open",
        Status::InProgress => "InProgress",
        Status::Resolved => "Resolved",
        Status::Closed => "Closed",
        Status::Escalated => "Escalated",
        Status::Reopened => "Reopened",
    }
}

fn main() {
    let cases = [
        ("A1", Status::Open, [Event::Start, Event::Resolve, Event::Close]),
        ("A2", Status::Open, [Event::Escalate, Event::Close, Event::Resolve]),
        ("A3", Status::Resolved, [Event::Close, Event::Reopen, Event::Start]),
    ];

    let mut lines = Vec::new();
    for (id, initial, events) in cases {
        let final_status = apply(initial, &events);
        if final_status == Status::InProgress {
            lines.push(format!("{} {}", id, label(Status::Reopened)));
        } else {
            lines.push(format!("{} {}", id, label(final_status)));
        }
    }

    print!("{}", lines.join("\n"));
}
"
  },
  "steps": [
