    "src/main.rs": "enum Reading {
    Temp(i32),
    Contact(bool),
    Power(bool),
    Missing,
}

enum Event {
    Sensor { id: &'static str, reading: Reading },
    Switch { room: &'static str, on: bool },
    Door { name: &'static str, open: bool },
}

fn main() {
    let events = [
        Event::Sensor {
            id: "s1",
            reading: Reading::Temp(29),
        },
        Event::Switch {
            room: "kitchen",
            on: false,
        },
        Event::Door {
            name: "front",
            open: true,
        },
        Event::Sensor {
            id: "s2",
            reading: Reading::Missing,
        },
    ];

    let mut warm = 0;
    let mut alerts = 0;
    let mut open_doors = 0;
    let mut switches_on = 0;
    let mut lines = Vec::new();

    for event in events {
        match event {
            Event::Sensor { id, reading } => match reading {
                Reading::Temp(c) if c >= 28 => {
                    warm += 1;
                    lines.push(format!("sensor:{id}=warm"));
                }
                Reading::Temp(_) => lines.push(format!("sensor:{id}=ok")),
                Reading::Contact(true) => {
                    alerts += 1;
                    lines.push(format!("sensor:{id}=alert"));
                }
                Reading::Contact(false) => lines.push(format!("sensor:{id}=clear")),
                Reading::Power(true) => lines.push(format!("sensor:{id}=powered")),
                Reading::Power(false) => {
                    alerts += 1;
                    lines.push(format!("sensor:{id}=power_loss"));
                }
                Reading::Missing => lines.push(format!("sensor:{id}=offline")),
            },
            Event::Switch { room, on } => {
                if on {
                    switches_on += 1;
                }
                lines.push(format!("switch:{room}={}", if on { "on" } else { "off" }));
            }
            Event::Door { name, open } => {
                if open {
                    open_doors += 1;
                }
                lines.push(format!("door:{name}={}", if open { "open" } else { "closed" }));
            }
        }
    }

    lines.push(format!(
        "summary warm={} alerts={} open_doors={} switches_on={}",
        warm, alerts, open_doors, switches_on
    ));

    print!("{}", lines.join("\n"));
}
