  "difficulty": "medium",
  "user": "Run the Rust crate at {project_root} and report the program output exactly.",
  "expected_tool_sequence": ["cargo_run"],
  "expected_output": "Room Atlas
accepted #1 09:00-10:30
rejected #2 10:15-11:00 overlaps #1
accepted #3 11:00-12:00
rejected #4 12:00-11:30 invalid
rejected #5 08:30-09:00 touches #1
accepted #6 12:00-13:00
accepted_count=3 rejected_count=3",
  "files": {
    "Cargo.toml": "[package]
name = "conference_room_booking_overlap_report"
version = "0.1.0"
edition = "2021"

[dependencies]
",
    "src/main.rs": "fn parse_hhmm(s: &str) -> i32 {
    let (h, m) = s.split_once(':').unwrap();
    h.parse::<i32>().unwrap() * 60 + m.parse::<i32>().unwrap()
}

#[derive(Clone, Copy)]
struct Booking {
    id: u32,
    start: i32,
    end: i32,
}

fn fmt_hhmm(minutes: i32) -> String {
    format!("{:02}:{:02}", minutes / 60, minutes % 60)
}

fn main() {
    let room = "Atlas";
    let requests = [
        (1_u32, "09:00", "10:30"),
        (2, "10:15", "11:00"),
        (3, "11:00", "12:00"),
        (4, "12:00", "11:30"),
        (5, "08:30", "09:00"),
        (6, "12:00", "13:00"),
    ];

    let mut accepted: Vec<Booking> = Vec::new();
    let mut lines: Vec<String> = Vec::new();
    let mut accepted_count = 0;
    let mut rejected_count = 0;

    lines.push(format!("Room {}", room));

    for (id, s, e) in requests {
        let start = parse_hhmm(s);
        let end = parse_hhmm(e);

        if end <= start {
            rejected_count += 1;
            lines.push(format!("rejected #{} {}-{} invalid", id, s, e));
            continue;
        }

        let mut conflict: Option<(u32, &'static str)> = None;
        for b in &accepted {
            if start < b.end && end > b.start {
                conflict = Some((b.id, "overlaps"));
                break;
            }
            if end == b.start || start == b.end {
                conflict = Some((b.id, "touches"));
                break;
            }
        }

        match conflict {
            Some((other, reason)) => {
                rejected_count += 1;
                lines.push(format!("rejected #{} {}-{} {} #{}", id, s, e, reason, other));
            }
            None => {
                accepted.push(Booking { id, start, end });
                accepted.sort_by_key(|b| (b.start, b.end, b.id));
                accepted_count += 1;
                lines.push(format!(
                    "accepted #{} {}-{}",
                    id,
                    fmt_hhmm(start),
                    fmt_hhmm(end)
                ));
            }
        }
    }

    lines.push(format!(
        "accepted_count={} rejected_count={}",
        accepted_count, rejected_count
    ));

    print!("{}", lines.join("\n"));
}
"
  },
  "steps": [
    {
      "tool": "cargo_run",
      "expect_status": "success"
    }
  ],
